import{_ as r,c as t,o as e,d as o}from"./app.f1e4bbc1.js";const d='{"title":"\u0414\u0432\u043E\u0440\u043E\u0432\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u0432 \u041E\u0442\u043A\u0440\u044B\u0442\u043E\u043C \u043F\u0430\u0432\u0438\u043B\u044C\u043E\u043D\u0435 \u0424\u0435\u0441\u0442\u0438\u0432\u0430\u043B\u044F \u041C\u043E\u0441\u043A\u043E\u0432\u0441\u043A\u043E\u0433\u043E \u0443\u0440\u0431\u0430\u043D\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0444\u043E\u0440\u0443\u043C\u0430","description":"","frontmatter":{"title":"\u0414\u0432\u043E\u0440\u043E\u0432\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u0432 \u041E\u0442\u043A\u0440\u044B\u0442\u043E\u043C \u043F\u0430\u0432\u0438\u043B\u044C\u043E\u043D\u0435 \u0424\u0435\u0441\u0442\u0438\u0432\u0430\u043B\u044F \u041C\u043E\u0441\u043A\u043E\u0432\u0441\u043A\u043E\u0433\u043E \u0443\u0440\u0431\u0430\u043D\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0444\u043E\u0440\u0443\u043C\u0430","date":"2015-10-01","cover":"16012113911_65d50ecefa_o.jpg"},"headers":[],"relativePath":"practice/event/dvorovaya-masterskaya-v-otkrytom-pavilone-festivalya-moskovskogo-urbanisticheskogo-foruma/index.md"}',n={},s=o('<p><strong>\u041E\u0442\u043A\u0440\u044B\u0442\u044B\u0439 \u043F\u0430\u0432\u0438\u043B\u044C\u043E\u043D \xAB\u0410\u043A\u0442\u0438\u0432\u0438\u0441\u0442\u0441\u043A\u0438\u0435 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438 \u043E\u0441\u0432\u043E\u0435\u043D\u0438\u044F \u0433\u043E\u0440\u043E\u0434\u0430\xBB</strong></p><p><strong>17 \u043E\u043A\u0442\u044F\u0431\u0440\u044F 2015 \u0441 10:00 \u0434\u043E 18:00</strong>, \u043D\u0430 <a href="http://fest2015.mosurbanforum.ru/" class="external-link" target="_blank" rel="noopener noreferrer">\u0424\u0435\u0441\u0442\u0438\u0432\u0430\u043B\u044C\u043D\u043E\u043C \u0434\u043D\u0435</a> <strong><a href="http://fest2015.mosurbanforum.ru/" class="external-link" target="_blank" rel="noopener noreferrer">5-\u0433\u043E \u041C\u043E\u0441\u043A\u043E\u0432\u0441\u043A\u043E\u0433\u043E \u0423\u0440\u0431\u0430\u043D\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0424\u043E\u0440\u0443\u043C\u0430</a></strong> \u0431\u0443\u0434\u0435\u0442 \u0440\u0430\u0431\u043E\u0442\u0430\u0442\u044C\xA0<strong><a href="http://fest2015.mosurbanforum.ru/open/" class="external-link" target="_blank" rel="noopener noreferrer">\u041E\u0442\u043A\u0440\u044B\u0442\u044B\u0439 \u043F\u0430\u0432\u0438\u043B\u044C\u043E\u043D</a></strong>\xA0\u2013 \u043C\u043D\u043E\u0433\u043E\u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u0430\u044F \u043F\u043B\u043E\u0449\u0430\u0434\u043A\u0430 \u0434\u043B\u044F \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0430\u043A\u0442\u0438\u0432\u0438\u0441\u0442\u0441\u043A\u0438\u0445 \u043F\u0440\u0430\u043A\u0442\u0438\u043A \u043E\u0441\u0432\u043E\u0435\u043D\u0438\u044F \u0433\u043E\u0440\u043E\u0434\u0430.</p><p>\u041F\u043E\u0441\u0442\u0438\u043D\u0434\u0443\u0441\u0442\u0440\u0438\u0430\u043B\u044C\u043D\u044B\u0439 \u0433\u043E\u0440\u043E\u0434 \u0432 \u0441\u0438\u043B\u0443 \u0441\u0432\u043E\u0435\u0439 \u0434\u0438\u043D\u0430\u043C\u0438\u0447\u043D\u043E\u0441\u0442\u0438, \u043D\u0435\u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u0443\u0435\u043C\u043E\u0441\u0442\u0438 \u0438 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043C\u0435\u043D\u044F\u044E\u0449\u0435\u0433\u043E\u0441\u044F \u043E\u0431\u0440\u0430\u0437\u0430 \u0436\u0438\u0437\u043D\u0438 \u0433\u043E\u0440\u043E\u0436\u0430\u043D \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u043D\u043E\u0432\u044B\u0445 \u043F\u043E\u0434\u0445\u043E\u0434\u043E\u0432 \u043A \u0438\u0437\u0443\u0447\u0435\u043D\u0438\u044E, \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044E \u0438 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044E. \u042D\u043A\u0441\u043F\u0435\u0440\u0442\u044B \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u044E\u0442 \u043D\u043E\u0432\u044B\u0435 \u043C\u0435\u0442\u043E\u0434\u044B \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0433\u043E\u0440\u043E\u0434\u0430, \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u043E\u0440\u044B \u2013 \u043D\u043E\u0432\u044B\u0435 \u043C\u043E\u0434\u0435\u043B\u0438 \u0434\u043B\u044F \u0435\u0433\u043E \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u0430\u0434\u043C\u0438\u043D\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u044F \u0440\u0430\u0437\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u043D\u043E\u0432\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F. \u0412 \u044D\u0442\u043E\u043C \u0436\u0435 \u043F\u043E\u043B\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0442 \u0438 \u0433\u043E\u0440\u043E\u0434\u0441\u043A\u0438\u0435 \u0430\u043A\u0442\u0438\u0432\u0438\u0441\u0442\u044B. \u041E\u043D\u0438 \u0438\u0437\u0443\u0447\u0430\u044E\u0442 \u0438 \u043C\u0435\u043D\u044F\u044E\u0442 \u0433\u043E\u0440\u043E\u0434 \u0442\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438, \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u044E\u0442 \u0438 \u043F\u0440\u043E\u0431\u0443\u044E\u0442 \u0440\u0430\u0437\u043D\u044B\u0435 \u0441\u0446\u0435\u043D\u0430\u0440\u0438\u0438 \u0435\u0433\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044F, \u0442\u0435\u043C \u0441\u0430\u043C\u044B\u043C \u0432\u043B\u0438\u044F\u044F \u043D\u0430 \u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043E\u0444\u0438\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0439 \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F.</p><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u0439 \u0432\u043E\u043F\u0440\u043E\u0441 \u041E\u0442\u043A\u0440\u044B\u0442\u043E\u0433\u043E \u043F\u0430\u0432\u0438\u043B\u044C\u043E\u043D\u0430 \u2013\xA0<strong>\u043A\u0430\u043A \u0433\u043E\u0440\u043E\u0434\u0441\u043A\u0438\u0435 \u0430\u043A\u0442\u0438\u0432\u0438\u0441\u0442\u044B \u0438 \u0441\u043E\u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430 \u0430\u0434\u0430\u043F\u0442\u0438\u0440\u0443\u044E\u0442\u0441\u044F \u043A \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430\u043C, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u043C \u0432 \u0433\u043E\u0440\u043E\u0434\u0435, \u0430 \u043F\u043E\u0442\u043E\u043C \u0430\u0434\u0430\u043F\u0442\u0438\u0440\u0443\u044E\u0442 \u0433\u043E\u0440\u043E\u0434 \xAB\u043F\u043E\u0434 \u0441\u0435\u0431\u044F\xBB?</strong>\xA0\u0412 \u0440\u0430\u043C\u043A\u0430\u0445 \u041E\u0442\u043A\u0440\u044B\u0442\u043E\u0433\u043E \u043F\u0430\u0432\u0438\u043B\u044C\u043E\u043D\u0430 \u0431\u0443\u0434\u0435\u0442 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D \u0441\u0440\u0435\u0437 \xAB\u043D\u0435-\u0444\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u044B\u0445\xBB \u043F\u0440\u0430\u043A\u0442\u0438\u043A \u043E\u0441\u0432\u043E\u0435\u043D\u0438\u044F \u0433\u043E\u0440\u043E\u0434\u0430 \u2013 \u043F\u043E\u0432\u0441\u0435\u0434\u043D\u0435\u0432\u043D\u044B\u0445, \u0445\u0443\u0434\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445, \u044D\u043A\u0441\u0442\u0440\u0435\u043C\u0430\u043B\u044C\u043D\u044B\u0445 \u0438 \u0434\u0440\u0443\u0433\u0438\u0445. \u041F\u043E\u0434 \xAB\u043D\u0435-\u0444\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u044B\u043C\xBB \u0432 \u0434\u0430\u043D\u043D\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442\u0441\u044F \u0441\u0442\u0438\u043B\u044C \u043F\u043E\u0434\u0445\u043E\u0434\u0430: \u043D\u0435 \u044D\u043A\u0441\u043F\u0435\u0440\u0442\u043D\u044B\u0439, \u0430 \u0432 \u0431\u043E\u043B\u044C\u0448\u0435\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438 \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u044B\u0439, \u0441\u0438\u0442\u0443\u0430\u0442\u0438\u0432\u043D\u044B\u0439.</p><p>\u041E\u0442\u043A\u0440\u044B\u0442\u044B\u0439 \u043F\u0430\u0432\u0438\u043B\u044C\u043E\u043D - \u044D\u0442\u043E \u0438\u043D\u0442\u0435\u0440\u0430\u043A\u0442\u0438\u0432\u043D\u0430\u044F \u043C\u0443\u043B\u044C\u0442\u0438\u0436\u0430\u043D\u0440\u043E\u0432\u0430\u044F \u043F\u043B\u043E\u0449\u0430\u0434\u043A\u0430, \u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u0443\u044E\u0449\u0430\u044F \u0438\u0434\u0435\u044E \u0432\u043E\u0432\u043B\u0435\u0447\u0435\u043D\u0438\u044F \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F \u0433\u043E\u0440\u043E\u0434\u0430 \u0447\u0435\u0440\u0435\u0437 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u0432\u0438\u0434\u044B \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0435\u0439. \u0412 \u0444\u043E\u0440\u043C\u0430\u0442\u0435 \u0432\u044B\u0441\u0442\u0430\u0432\u043E\u043A, \u0434\u0438\u0441\u043A\u0443\u0441\u0441\u0438\u0439, \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0445 \u043F\u0440\u0435\u0437\u0435\u043D\u0442\u0430\u0446\u0438\u0439, \u0432\u043E\u0440\u043A\u0448\u043E\u043F\u043E\u0432 \u0436\u0438\u0442\u0435\u043B\u0438 \u0433\u043E\u0440\u043E\u0434\u0430, \u0445\u0443\u0434\u043E\u0436\u043D\u0438\u043A\u0438, \u0442\u0430\u043D\u0446\u043E\u0440\u044B, \u043C\u0443\u0437\u044B\u043A\u0430\u043D\u0442\u044B, \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u0430\u043B\u0438\u0441\u0442\u044B, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u0442\u0435\u043B\u0438 \u0440\u0430\u0437\u043D\u044B\u0445 \u0433\u043E\u0440\u043E\u0434\u0441\u043A\u0438\u0445 \u0438\u043D\u0438\u0446\u0438\u0430\u0442\u0438\u0432 \u0438 \u0441\u043E\u043E\u0431\u0449\u0435\u0441\u0442\u0432 \u043F\u043E\u043A\u0430\u0436\u0443\u0442 \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0430\u043C \u043F\u0440\u0438\u043C\u0435\u0440\u044B \u0441\u0432\u043E\u0438\u0445 \u043F\u0440\u043E\u0435\u043A\u0442\u043E\u0432 \u0432 \u0433\u043E\u0440\u043E\u0434\u0435 \u0438 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0430\u0442 \u043F\u043E\u0443\u0447\u0430\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0432 \u043D\u0438\u0445.</p><p>\u041F\u043E\u0434\u043E\u0431\u043D\u044B\u0439 \u0444\u043E\u0440\u043C\u0430\u0442 \u0431\u044B\u043B \u0432\u043F\u0435\u0440\u0432\u044B\u0435 \u043E\u043F\u0440\u043E\u0431\u043E\u0432\u0430\u043D \u0432 2014 \u0433\u043E\u0434\u0443 \u043D\u0430 \u0424\u0435\u0441\u0442\u0438\u0432\u0430\u043B\u044C\u043D\u043E\u043C \u0434\u043D\u0435 4-\u0433\u043E \u041C\u043E\u0441\u043A\u043E\u0432\u0441\u043A\u043E\u0433\u043E \u0443\u0440\u0431\u0430\u043D\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0444\u043E\u0440\u0443\u043C\u0430. \u041D\u0430 \u044D\u0442\u043E\u0442 \u0440\u0430\u0437 \u041E\u0442\u043A\u0440\u044B\u0442\u044B\u0439 \u043F\u0430\u0432\u0438\u043B\u044C\u043E\u043D \u0431\u0443\u0434\u0435\u0442 \u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0432 \u0432\u0438\u0434\u0435 \xABpop-up school\xBB (\u0432 \u0434\u043E\u0441\u043B\u043E\u0432\u043D\u043E\u043C \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0435 - \xAB\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u0430\u044F \u0448\u043A\u043E\u043B\u0430\xBB), \u0447\u0442\u043E \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0437\u0430\u0434\u0430\u0447\u0435 \u043F\u0440\u0435\u0437\u0435\u043D\u0442\u043E\u0432\u0430\u0442\u044C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438 \u0438 \u043D\u0430\u0443\u0447\u0438\u0442\u044C \u0436\u0438\u0442\u0435\u043B\u0435\u0439 \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u043C \u0442\u0430\u043A\u0442\u0438\u043A\u0430\u043C \u0443\u043B\u0443\u0447\u0448\u0435\u043D\u0438\u044F \u0433\u043E\u0440\u043E\u0434\u0430.</p><p>\u0421\u0440\u0435\u0434\u0438 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 <a href="http://fest2015.mosurbanforum.ru/open/adult/" class="external-link" target="_blank" rel="noopener noreferrer">\u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0445 \u0441\u0435\u043A\u0446\u0438\u0439 \u041F\u0430\u0432\u0438\u043B\u044C\u043E\u043D\u0430</a> \u043A\u043E\u043C\u0430\u043D\u0434\u0430 <strong>OOLEY</strong>\xA0\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0435 \u0443\u0447\u0430\u0441\u0442\u0438\u0435 \u0432 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 <strong>\u0434\u0432\u043E\u0440\u043E\u0432\u043E\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439</strong>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043D\u0430\u043F\u043E\u043B\u043D\u0438\u0442\u0441\u044F \u0432\u0441\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0439 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0439 \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C\u044E \u0438 \u043F\u043E\u043C\u043E\u0436\u0435\u0442 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0438\u0442\u044C \u0432 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435 &quot;\u043D\u0435-\u0444\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u044B\u0435&quot; \u0430\u043A\u0442\u0438\u0432\u0438\u0441\u0442\u0441\u043A\u0438\u0435 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438.</p><p><strong>\u0414\u0432\u043E\u0440\u043E\u0432\u0430\u044F \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F</strong></p><p>\u0417\u043E\u043D\u0430 \u0440\u0443\u0447\u043D\u043E\u0433\u043E \u0442\u0440\u0443\u0434\u0430, \u0432 \u0440\u0430\u043C\u043A\u0430\u0445 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0443 \u043F\u043E\u0441\u0435\u0442\u0438\u0442\u0435\u043B\u0435\u0439 \u0431\u0443\u0434\u0435\u0442 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0441\u043E\u0437\u0434\u0430\u0442\u044C \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0434\u043B\u044F \xAB\u043D\u0438\u0437\u043E\u0432\u043E\u0433\u043E\xBB \u043F\u0440\u0435\u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0438\u044F \u0433\u043E\u0440\u043E\u0434\u0430 \u0438 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u043E-\u043A\u0443\u043B\u044C\u0442\u0443\u0440\u043D\u044B\u0445 \u0438\u043D\u0438\u0446\u0438\u0430\u0442\u0438\u0432.</p><p>\u041F\u043B\u0430\u043D\u0438\u0440\u0443\u0435\u043C\u044B\u0435 \u0432\u043E\u0440\u043A\u0448\u043E\u043F\u044B:</p><ul><li><strong>\u0418\u0437\u0433\u043E\u0442\u043E\u0432\u043B\u0435\u043D\u0438\u0435 \xAB\u041F\u0430\u0432\u0438\u043B\u044C\u043E\u043D\u0430 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0438\u043A\u0430\xBB</strong> -\xA0\xA0\xA0\u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u0438 \u0434\u043B\u044F \u043F\u0440\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u043E\u0431\u0440\u0430\u043D\u0438\u0439 \u043B\u043E\u043A\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F</li><li><strong>\u0418\u0437\u0433\u043E\u0442\u043E\u0432\u043B\u0435\u043D\u0438\u0435 \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u0435\u0439 \u0438 \u0432\u044B\u0432\u0435\u0441\u043E\u043A \u0434\u043B\u044F \u0433\u043E\u0440\u043E\u0434\u0441\u043A\u0438\u0445 \u0438\u043D\u0438\u0446\u0438\u0430\u0442\u0438\u0432</strong></li><li><strong>\u0418\u0437\u0433\u043E\u0442\u043E\u0432\u043B\u0435\u043D\u0438\u0435 \u044F\u0449\u0438\u043A\u043E\u0432 \u0434\u043B\u044F \u0440\u0430\u0441\u0441\u0430\u0434\u044B, \u043A\u043E\u043D\u0442\u0435\u0439\u043D\u0435\u0440\u043E\u0432 \u0434\u043B\u044F \u043C\u0430\u043A\u0443\u043B\u0430\u0442\u0443\u0440\u044B, \u0437\u0430\u0449\u0438\u0442\u043D\u044B\u0445</strong></li></ul><p><strong>\u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u0439 \u043D\u0430 \u0434\u0435\u0440\u0435\u0432\u044C\u044F, \u043C\u0438\u043D\u0438\u0433\u043E\u043B\u0443\u0431\u044F\u0442\u043D\u0438, \u0431\u0435\u043B\u044C\u0447\u0430\u0442\u043D\u0438\u043A\u0430</strong></p><ul><li><strong>\u0418\u0437\u0433\u043E\u0442\u043E\u0432\u043B\u0435\u043D\u0438\u0435 \u043C\u043E\u0431\u0438\u043B\u044C\u043D\u043E\u0439 \u0438 \u0441\u0442\u0430\u0446\u0438\u043E\u043D\u0430\u0440\u043D\u043E\u0439 \u0443\u043B\u0438\u0447\u043D\u043E\u0439 \u043C\u0435\u0431\u0435\u043B\u0438</strong></li></ul><p>\u041F\u0440\u0438\u0433\u043B\u0430\u0448\u0430\u0435\u043C \u0432\u0441\u0435\u0445 \u0437\u0430\u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043E\u0432\u0430\u043D\u043D\u044B\u0445 \u0432\xA0\u0441\u043E\u0432\u043C\u0435\u0441\u0442\u043D\u043E\u043C \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u043C \u043F\u0435\u0440\u0435\u043E\u0441\u043C\u044B\u0441\u043B\u0435\u043D\u0438\u0438 \u0433\u043E\u0440\u043E\u0434\u0430 \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442\u044C \u043D\u0430 \u0424\u0435\u0441\u0442\u0438\u0432\u0430\u043B\u044C, \u0437\u0430\u0433\u043B\u044F\u0434\u044B\u0432\u0430\u0442\u044C \u0432 \u041E\u0442\u043A\u0440\u044B\u0442\u044B\u0439 \u043F\u0430\u0432\u0438\u043B\u044C\u043E\u043D \u0438 \u0432\u043A\u043B\u044E\u0447\u0430\u0442\u044C\u0441\u044F \u0432 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0439 \u0430\u043A\u0442\u0438\u0432\u0438\u0437\u043C \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u043D\u0430\u043C\u0438. \u0412\u0445\u043E\u0434 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439.</p>',14),a=[s];function p(l,g,_,i,c,u){return e(),t("div",null,a)}var m=r(n,[["render",p]]);export{d as __pageData,m as default};
